个人中心到信息绑定主页新用户登陆成功后，返回user/index.vue界面使用 标签关联子页面 通过cookie获取userInfopages/user.vue 1234567891011121314151617181920212223242526272829303132333435363738394041424344&lt;template&gt; &lt;!--个人中心--&gt; &lt;div class=&quot;wrapper wbgcolor&quot;&gt; &lt;div class=&quot;w1200 personal&quot;&gt; &lt;div class=&quot;credit-ad&quot;&gt; &lt;img src=&quot;~/assets/images/clist1.jpg&quot; width=&quot;1200&quot; height=&quot;96&quot;/&gt; &lt;/div&gt; &lt;div class=&quot;personal-left&quot;&gt; &lt;InvestorNav v-if=&quot;userType === 1&quot;/&gt; &lt;BorrowerNav v-if=&quot;userType === 2&quot;/&gt; &lt;/div&gt; &lt;NuxtChild/&gt; &lt;div class=&quot;clear&quot;&gt;&lt;/div&gt; &lt;/div&gt; &lt;/div&gt;&lt;/template&gt;&lt;script&gt; import &#x27;~/assets/css/user.css&#x27; import InvestorNav from &#x27;~/components/InvestorNav&#x27; import BorrowerNav from &#x27;~/components/BorrowerNav&#x27; import cookie from &#x27;js-cookie&#x27; export default &#123; components: &#123; InvestorNav, BorrowerNav, &#125;, data() &#123; return &#123; userType: 0, &#125; &#125;, mounted() &#123; let userInfo = cookie.get(&#x27;userInfo&#x27;) if (userInfo) &#123; userInfo = JSON.parse(userInfo) this.userType = userInfo.userType &#125; &#125;, &#125;&lt;/script&gt; 填写绑定点击立即开通,路由是user/bind.vuepages/user/index.vue 123456&lt;li&gt; 您还未开通第三方支付账户，请 &lt;NuxtLink to=&quot;/user/bind&quot;&gt;立即开通&lt;/NuxtLink&gt; 以确保您的正常使用和资金安全。&lt;/li&gt; 新建bind页面，用于填写用户绑定数据 pages/user/bind.vue 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115&lt;template&gt; &lt;div class=&quot;personal-main&quot;&gt; &lt;div class=&quot;personal-pay&quot;&gt; &lt;h3&gt;&lt;i&gt;开通第三方账户&lt;/i&gt;&lt;/h3&gt; &lt;div class=&quot;pay-notice&quot;&gt; &lt;p&gt;请开通汇付宝存管账户以便于您正常理财&lt;/p&gt; &lt;/div&gt; &lt;div class=&quot;pay-form&quot;&gt; &lt;ul&gt; &lt;li&gt; &lt;label&gt;真实姓名&lt;/label&gt; &lt;input v-model=&quot;userBind.name&quot; type=&quot;text&quot; class=&quot;pay-txt&quot; maxlength=&quot;16&quot; placeholder=&quot;您的真实姓名&quot; /&gt; &lt;/li&gt; &lt;li&gt; &lt;label&gt;身份证号&lt;/label&gt; &lt;input v-model=&quot;userBind.idCard&quot; type=&quot;text&quot; class=&quot;pay-txt&quot; maxlength=&quot;18&quot; placeholder=&quot;您的身份证号&quot; /&gt; &lt;div id=&quot;idCardErrorDiv&quot;&gt; &lt;p style=&quot;margin-top: 10px&quot;&gt; 身份证信息认证后将不可修改，请您仔细填写 &lt;/p&gt; &lt;/div&gt; &lt;/li&gt; &lt;li&gt; &lt;label&gt;绑定银行&lt;/label&gt; &lt;input v-model=&quot;userBind.bankType&quot; type=&quot;text&quot; class=&quot;pay-txt&quot; placeholder=&quot;银行名称&quot; /&gt; &lt;/li&gt; &lt;li&gt; &lt;label&gt;银行卡号&lt;/label&gt; &lt;input v-model=&quot;userBind.bankNo&quot; type=&quot;text&quot; class=&quot;pay-txt&quot; placeholder=&quot;本人持有的银行卡&quot; /&gt; &lt;/li&gt; &lt;li&gt; &lt;label&gt;预留手机&lt;/label&gt; &lt;input v-model=&quot;userBind.mobile&quot; type=&quot;text&quot; class=&quot;pay-txt&quot; placeholder=&quot;银行卡预留手机号&quot; /&gt; &lt;/li&gt; &lt;li&gt; &lt;label&gt;&amp;nbsp;&lt;/label&gt; &lt;input v-model=&quot;agree&quot; type=&quot;checkbox&quot;/&gt; 我已阅读并同意 &lt;a href=&quot;#&quot; class=&quot;c-orange&quot; target=&quot;_blank&quot;&gt; 《汇付宝托管账户协议》 &lt;/a&gt; &lt;/li&gt; &lt;li&gt; &lt;label&gt;&amp;nbsp;&lt;/label&gt; &lt;el-button :disabled=&quot;!agree&quot; @click=&quot;commitBind()&quot; type=&quot;primary&quot;&gt; 开户 &lt;/el-button&gt; &lt;/li&gt; &lt;/ul&gt; &lt;/div&gt; &lt;/div&gt; &lt;/div&gt;&lt;/template&gt;# js&lt;script&gt; export default &#123; data() &#123; return &#123; agree: false, userBind: &#123;&#125;, &#125; &#125;, methods: &#123; commitBind() &#123; this.$alert( &#x27;&lt;div style=&quot;size: 18px;color: red;&quot;&gt;您即将前往汇付宝绑定账号&lt;/div&gt;&#x27;, &#x27;前往汇付宝资金托管平台&#x27;, &#123; dangerouslyUseHTMLString: true, confirmButtonText: &#x27;立即前往&#x27;, callback: (action) =&gt; &#123; if (action === &#x27;confirm&#x27;) &#123; this.$axios .$post(&#x27;/api/core/userBind/auth/bind&#x27;, this.userBind) .then((response) =&gt; &#123; document.write(response.data.formStr) &#125;) &#125; &#125;, &#125; ) &#125;, &#125;, &#125;&lt;/script&gt; 信息绑定与回调页面 用户点击”开户”后，下一步用户页面跳转汇付宝开户=&gt;立即前往=&gt;尚融宝保存=&gt;调用hfbapi=&gt;生成一个form表单=&gt;返回客户端浏览器=&gt;浏览器跳转汇付宝=&gt;用户在汇付宝页面确认=&gt;汇付宝生成账户信息=&gt;汇付宝回调尚融宝接口=&gt;尚融宝保存bindCode 前置准备导入hfb项目,端口9999 导入hfb.sql 参考文档data/汇付宝商户账户技术文档.docx 添加依赖service-base中添加依赖 12345 &lt;!-- json解析 --&gt;&lt;dependency&gt; &lt;groupId&gt;com.alibaba&lt;/groupId&gt; &lt;artifactId&gt;fastjson&lt;/artifactId&gt;&lt;/dependency&gt; 添加工具类common/src/main/java/com/qy/common/utils/HttpUtils.java 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990@Slf4jpublic final class HttpUtils &#123; static final String POST = &quot;POST&quot;; static final String GET = &quot;GET&quot;; static final int CONN_TIMEOUT = 30000;// ms static final int READ_TIMEOUT = 30000;// ms /** * post 方式发送http请求. * * @param strUrl * @param reqData * @return */ public static byte[] doPost(String strUrl, byte[] reqData) &#123; return send(strUrl, POST, reqData); &#125; /** * get方式发送http请求. * * @param strUrl * @return */ public static byte[] doGet(String strUrl) &#123; return send(strUrl, GET, null); &#125; /** * @param strUrl * @param reqmethod * @param reqData * @return */ public static byte[] send(String strUrl, String reqmethod, byte[] reqData) &#123; try &#123; URL url = new URL(strUrl); HttpURLConnection httpcon = (HttpURLConnection) url.openConnection(); httpcon.setDoOutput(true); httpcon.setDoInput(true); httpcon.setUseCaches(false); httpcon.setInstanceFollowRedirects(true); httpcon.setConnectTimeout(CONN_TIMEOUT); httpcon.setReadTimeout(READ_TIMEOUT); httpcon.setRequestMethod(reqmethod); httpcon.connect(); if (reqmethod.equalsIgnoreCase(POST)) &#123; OutputStream os = httpcon.getOutputStream(); os.write(reqData); os.flush(); os.close(); &#125; BufferedReader in = new BufferedReader(new InputStreamReader(httpcon.getInputStream(), &quot;utf-8&quot;)); String inputLine; StringBuilder bankXmlBuffer = new StringBuilder(); while ((inputLine = in.readLine()) != null) &#123; bankXmlBuffer.append(inputLine); &#125; in.close(); httpcon.disconnect(); return bankXmlBuffer.toString().getBytes(); &#125; catch (Exception ex) &#123; log.error(ex.toString(), ex); return null; &#125; &#125; /** * 从输入流中读取数据 * * @param inStream * @return * @throws Exception */ public static byte[] readInputStream(InputStream inStream) throws Exception &#123; ByteArrayOutputStream outStream = new ByteArrayOutputStream(); byte[] buffer = new byte[1024]; int len = 0; while ((len = inStream.read(buffer)) != -1) &#123; outStream.write(buffer, 0, len); &#125; byte[] data = outStream.toByteArray();// 网页的二进制数据 outStream.close(); inStream.close(); return data; &#125;&#125; service-core/src/main/java/com/qy/core/hfb/FormHelper.java 123456789101112131415161718192021222324252627282930313233343536373839public class FormHelper &#123; /** * 构建自动提交form表单 * @param url 表单提交的url * @param paramMap 表单的提交项 * @return */ public static String buildForm(String url, Map&lt;String, Object&gt; paramMap) &#123; StringBuffer inputStr = new StringBuffer(); Iterator&lt;Map.Entry&lt;String, Object&gt;&gt; entries = paramMap.entrySet().iterator(); while (entries.hasNext()) &#123; Map.Entry&lt;String, Object&gt; entry = entries.next(); String key = entry.getKey(); Object value = entry.getValue(); inputStr.append(&quot;&lt;input type=&#x27;hidden&#x27; name=&#x27;&quot; + key + &quot;&#x27; value=&#x27;&quot; + value + &quot;&#x27;/&gt;&quot;); &#125; String formStr = &quot;&lt;!DOCTYPE html&gt;
&quot; + &quot;&lt;html lang=\&quot;en\&quot; xmlns:th=\&quot;http://www.thymeleaf.org\&quot;&gt;
&quot; + &quot;&lt;head&gt;
&quot; + &quot;&lt;/head&gt;
&quot; + &quot;&lt;body&gt;
&quot; + &quot;&lt;form name=\&quot;form\&quot; action=\&quot;&quot; + url + &quot;\&quot; method=\&quot;post\&quot;&gt;
&quot; + inputStr + &quot;&lt;/form&gt;
&quot; + &quot;&lt;script&gt;
&quot; + &quot;	document.form.submit();
&quot; + &quot;&lt;/script&gt;
&quot; + &quot;&lt;/body&gt;
&quot; + &quot;&lt;/html&gt;&quot;; return formStr; &#125;&#125; service-core/src/main/java/com/qy/core/hfb/HfbConst.java 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768/** * 汇付宝常量定义 */public class HfbConst &#123; //给商户分配的唯一标识 public static final String AGENT_ID = &quot;999888&quot;; //签名key public static final String SIGN_KEY = &quot;9876543210&quot;; /** * 用户绑定 */ //用户绑定汇付宝平台url地址 public static final String USERBIND_URL = &quot;http://localhost:9999/userBind/BindAgreeUserV2&quot;; //用户绑定异步回调 public static final String USERBIND_NOTIFY_URL = &quot;http://localhost/api/core/userBind/notify&quot;; //用户绑定同步回调 public static final String USERBIND_RETURN_URL = &quot;http://localhost:3000/user&quot;; /** * 充值 */ //充值汇付宝平台url地址 public static final String RECHARGE_URL = &quot;http://localhost:9999/userAccount/AgreeBankCharge&quot;; //充值异步回调 public static final String RECHARGE_NOTIFY_URL = &quot;http://localhost/api/core/userAccount/notify&quot;; //充值同步回调 public static final String RECHARGE_RETURN_URL = &quot;http://localhost:3000/user&quot;; /** * 投标 */ //充值汇付宝平台url地址 public static final String INVEST_URL = &quot;http://localhost:9999/userInvest/AgreeUserVoteProject&quot;; //充值异步回调 public static final String INVEST_NOTIFY_URL = &quot;http://localhost/api/core/lendItem/notify&quot;; //充值同步回调 public static final String INVEST_RETURN_URL = &quot;http://localhost:3000/user&quot;; /** * 放款 */ public static final String MAKE_LOAD_URL = &quot;http://localhost:9999/userInvest/AgreeAccountLendProject&quot;; /** * 提现 */ //充值汇付宝平台url地址 public static final String WITHDRAW_URL = &quot;http://localhost:9999/userAccount/CashBankManager&quot;; //充值异步回调 public static final String WITHDRAW_NOTIFY_URL = &quot;http://localhost/api/core/userAccount/notifyWithdraw&quot;; //充值同步回调 public static final String WITHDRAW_RETURN_URL = &quot;http://localhost:3000/user&quot;; /** * 还款扣款 */ //充值汇付宝平台url地址 public static final String BORROW_RETURN_URL = &quot;http://localhost:9999/lendReturn/AgreeUserRepayment&quot;; //充值异步回调 public static final String BORROW_RETURN_NOTIFY_URL = &quot;http://localhost/api/core/lendReturn/notifyUrl&quot;; //充值同步回调 public static final String BORROW_RETURN_RETURN_URL = &quot;http://localhost:3000/user&quot;;&#125; service-core/src/main/java/com/qy/core/hfb/RequestHelper.java 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768697071727374757677787980818283848586878889909192939495@Slf4jpublic class RequestHelper &#123; public static void main(String[] args) &#123; Map&lt;String, Object&gt; paramMap = new HashMap&lt;&gt;(); paramMap.put(&quot;d&quot;, &quot;4&quot;); paramMap.put(&quot;b&quot;, &quot;2&quot;); paramMap.put(&quot;c&quot;, &quot;3&quot;); paramMap.put(&quot;a&quot;, &quot;1&quot;); &#125; /** * 请求数据获取签名 * @param paramMap * @return */ public static String getSign(Map&lt;String, Object&gt; paramMap) &#123; if (paramMap.containsKey(&quot;sign&quot;)) &#123; paramMap.remove(&quot;sign&quot;); &#125; TreeMap&lt;String, Object&gt; sorted = new TreeMap&lt;&gt;(paramMap); StringBuilder str = new StringBuilder(); for (Map.Entry&lt;String, Object&gt; param : sorted.entrySet()) &#123; str.append(param.getValue()).append(&quot;|&quot;); &#125; str.append(HfbConst.SIGN_KEY); log.info(&quot;加密前：&quot; + str.toString()); String md5Str = MD5.encrypt(str.toString()); log.info(&quot;加密后：&quot; + md5Str); return md5Str; &#125; /** * Map转换 * @param paramMap * @return */ public static Map&lt;String, Object&gt; switchMap(Map&lt;String, String[]&gt; paramMap) &#123; Map&lt;String, Object&gt; resultMap = new HashMap&lt;&gt;(); for (Map.Entry&lt;String, String[]&gt; param : paramMap.entrySet()) &#123; resultMap.put(param.getKey(), param.getValue()[0]); &#125; return resultMap; &#125; /** * 签名校验 * @param paramMap * @return */ public static boolean isSignEquals(Map&lt;String, Object&gt; paramMap) &#123; String sign = (String) paramMap.get(&quot;sign&quot;); String md5Str = getSign(paramMap); if (!sign.equals(md5Str)) &#123; return false; &#125; return true; &#125; /** * 获取时间戳 * @return */ public static long getTimestamp() &#123; return new Date().getTime(); &#125; /** * 封装同步请求 * @param paramMap * @param url * @return */ public static JSONObject sendRequest(Map&lt;String, Object&gt; paramMap, String url) &#123; String result = &quot;&quot;; try &#123; //封装post参数 StringBuilder postdata = new StringBuilder(); for (Map.Entry&lt;String, Object&gt; param : paramMap.entrySet()) &#123; postdata.append(param.getKey()).append(&quot;=&quot;) .append(param.getValue()).append(&quot;&amp;&quot;); &#125; log.info(String.format(&quot;--&gt; 发送请求到汇付宝：post data %1s&quot;, postdata)); byte[] reqData = postdata.toString().getBytes(&quot;utf-8&quot;); byte[] respdata = HttpUtils.doPost(url, reqData); result = new String(respdata); log.info(String.format(&quot;--&gt; 汇付宝应答结果：result data %1s&quot;, result)); &#125; catch (Exception ex) &#123; ex.printStackTrace(); &#125; return JSONObject.parseObject(result); &#125;&#125; 接口service-core/src/main/java/com/qy/core/controller/api/ApiUserBindController.java 12345678910111213141516171819@Api(tags = &quot;会员账号绑定&quot;)@RestController@RequestMapping(&quot;/api/core/userBind&quot;)@Slf4jpublic class ApiUserBindController &#123; @Resource private UserBindService userBindService; @ApiOperation(&quot;账户绑定提交数据&quot;) @PostMapping(&quot;/auth/bind&quot;) public R bind(@RequestBody UserBindVO userBindVO, HttpServletRequest request) &#123; String token = request.getHeader(&quot;token&quot;); Long userId = JwtUtils.getUserId(token); String formStr = userBindService.commitBindUser(userBindVO, userId); return R.ok().data(&quot;formStr&quot;, formStr); &#125;&#125; 实现UserBindServiceImpl.java 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556@Servicepublic class UserBindServiceImpl extends ServiceImpl&lt;UserBindMapper, UserBind&gt; implements UserBindService &#123; @Override public String commitBindUser(UserBindVO userBindVO, Long userId) &#123; //查询身份证号码是否绑定 QueryWrapper&lt;UserBind&gt; userBindQueryWrapper = new QueryWrapper&lt;&gt;(); userBindQueryWrapper .eq(&quot;id_card&quot;, userBindVO.getIdCard()) .ne(&quot;user_id&quot;, userId); UserBind userBind = baseMapper.selectOne(userBindQueryWrapper); //USER_BIND_IDCARD_EXIST_ERROR(-301, &quot;身份证号码已绑定&quot;), Assert.isNull(userBind, ResponseEnum.USER_BIND_IDCARD_EXIST_ERROR); //查询用户绑定信息 userBindQueryWrapper = new QueryWrapper&lt;&gt;(); userBindQueryWrapper.eq(&quot;user_id&quot;, userId); userBind = baseMapper.selectOne(userBindQueryWrapper); //判断是否有绑定记录 if (userBind == null) &#123; //如果未创建绑定记录，则创建一条记录 userBind = new UserBind(); BeanUtils.copyProperties(userBindVO, userBind); userBind.setUserId(userId); userBind.setStatus(UserBindEnum.NO_BIND.getStatus()); baseMapper.insert(userBind); &#125; else &#123; //曾经跳转到托管平台，但是未操作完成，此时将用户最新填写的数据同步到userBind对象 BeanUtils.copyProperties(userBindVO, userBind); baseMapper.updateById(userBind); &#125; Map&lt;String, Object&gt; paramMap = new HashMap&lt;&gt;(); paramMap.put(&quot;agentId&quot;, HfbConst.AGENT_ID); paramMap.put(&quot;agentUserId&quot;, userId); paramMap.put(&quot;idCard&quot;, userBindVO.getIdCard()); paramMap.put(&quot;personalName&quot;, userBindVO.getName()); paramMap.put(&quot;bankType&quot;, userBindVO.getBankType()); paramMap.put(&quot;bankNo&quot;, userBindVO.getBankNo()); paramMap.put(&quot;mobile&quot;, userBindVO.getMobile()); paramMap.put(&quot;returnUrl&quot;, HfbConst.USERBIND_RETURN_URL); paramMap.put(&quot;notifyUrl&quot;, HfbConst.USERBIND_NOTIFY_URL); paramMap.put(&quot;timestamp&quot;, RequestHelper.getTimestamp()); paramMap.put(&quot;sign&quot;, RequestHelper.getSign(paramMap)); //构建充值自动提交表单 String formStr = FormHelper.buildForm(HfbConst.USERBIND_URL, paramMap); return formStr; &#125;&#125; 结果hfb服务返回的formStr生成的表单,hfb数据库生成用户信息 绑定功能回调在hfb设置支付密码后,点击确认，hfb回调给srb数据 接口ApiUserBindController 123456789101112 @ApiOperation(&quot;回调&quot;)@PostMapping(&quot;/notify&quot;)public String notifySrb(HttpServletRequest request)&#123; // 1.获得参数 Map&lt;String, String[]&gt;parameterMap=request.getParameterMap(); //2. 验签 Map&lt;String, Object&gt; map=RequestHelper.switchMap(parameterMap); boolean signEquals=RequestHelper.isSignEquals(map); Assert.isTrue(signEquals,ResponseEnum.WEIXIN_CALLBACK_PARAM_ERROR); userBindService.notifySrb(map); return&quot;success&quot;; &#125; 实现123456789101112131415161718192021222324 @Overridepublic void notifySrb(Map&lt;String, Object&gt; map)&#123; // 获取参数 String result_code=(String)map.get(&quot;resultCode&quot;); String bind_code=(String)map.get(&quot;bindCode&quot;); String agent_user_id=(String)map.get(&quot;agentUserId&quot;); // 更新用户绑定信息 QueryWrapper&lt;UserBind&gt; userBindQueryWrapper=new QueryWrapper&lt;&gt;(); userBindQueryWrapper.eq(&quot;user_id&quot;,agent_user_id); UserBind userBind=baseMapper.selectOne(userBindQueryWrapper); userBind.setBindCode(bind_code); userBind.setStatus(UserBindEnum.BIND_OK.getStatus()); baseMapper.updateById(userBind); // 更新用户信息 UserInfo userInfo=userInfoMapper.selectById(agent_user_id); userInfo.setName(userBind.getName()); userInfo.setIdCard(userBind.getIdCard()); userInfo.setBindCode(bind_code); userInfo.setBindStatus(UserBindEnum.BIND_OK.getStatus()); userInfoMapper.updateById(userInfo); &#125; &#125; 结果user_info表，user_bind表数据被修改
